/// <summary>
///
/// </summary>
public void dialog()
{
    Dialog                       dialog;
    ETGIntegrationInvoice        arAPRef;
    DialogField                  dialogArAPRef;
    ;

    dialog = new dialog("Integration status update");
    dialogArAPRef = dialog.addField(extendedTypeStr(ETGIntegrationInvoice), "Invoice number");
    dialog.run();

    if(!dialogArAPRef.value())
    {
        throw error("Invoice number should be fill");
    }
    else if (dialog.run())
    {
        this.create(dialogArAPRef.value());
    }

}

/// <summary>
///
/// </summary>
/// <param name = "_fromdate"></param>
/// <param name = "_todate"></param>
public void create(ETGIntegrationInvoice arAPRef)
{
    ETG_ARAP_MSGHEADER headerMsg, _headerMsg;
    ETG_ARAP_MSGLINES  MsgLines, _MsgLines;
    LedgerJournalTrans ledgerJournalTrans;
    LedgerJournalTable ledgerJournalTable;

    str _arAPRef = arAPRef;

    ttsbegin;
    select forupdate headerMsg where headerMsg.ETGARAPREF == _arAPRef;

    if(headerMsg)
    {
        select * from ledgerJournalTrans
            where ledgerJournalTrans.Invoice == headerMsg.ETGARAPREF;

        select * from ledgerJournalTable
            where ledgerJournalTable.JournalNum == ledgerJournalTrans.JournalNum
            && ledgerJournalTable.Posted == NoYes::Yes;
        if(ledgerJournalTable)
        {
            headerMsg.ETGIntegrationsStatus = ETGIntegrationStatus::Processed;
            headerMsg.ETGLOG = "";
            headerMsg.update();
            ttscommit;
            info(strFmt("The Invoice %1 status is Processed", headerMsg.ETGARAPREF));
        }
    }
    else
    {
        ttsbegin;
        headerMsg.ETGIntegrationsStatus = ETGIntegrationStatus::Error;
        headerMsg.update();
        ttscommit;
        info(strFmt("The Invoice %1 status is Error", headerMsg.ETGARAPREF));
    }

}

/// <summary>
///
/// </summary>
/// <param name = "_args"></param>
public static void main(Args _args)
{
    ETGIntegrationStatusUpdate statusUpdate;

    statusUpdate = new ETGIntegrationStatusUpdate();
    statusUpdate.run();
}
